1	/**
2	 * Activity Logs API Route
3	 *
4	 * This route handles activity log management including fetching and creating activity logs.
5	 *
6	 * @module app/api/activity-logs/route
7	 */
8	
9	import {
10	  calculateChanges,
11	  mapDeletedFieldsToChanges,
12	} from '@/app/api/lib/helpers/activityLogger';
13	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
14	import { ActivityLog } from '@/app/api/lib/models/activityLog';
15	import { GamingLocations } from '@/app/api/lib/models/gaminglocations';
16	import { Machine } from '@/app/api/lib/models/machines';
17	import User from '@/app/api/lib/models/user';
18	import { generateMongoId } from '@/lib/utils/id';
19	import { formatIPForDisplay, getIPInfo } from '@/lib/utils/ipAddress';
20	import {
21	  logRouteFetch,
22	  logRouteCreate,
23	  logRouteDelete,
24	  logRouteError,
25	  extractUserFromRequest,
26	} from '@/app/api/lib/utils/routeLogger';
27	import type {
28	  ActivityLogDocument,
29	  GamingLocationDocument,
30	  GamingMachine,
31	} from '@/shared/types';
32	import type { LeanUserDocument } from '@/shared/types/auth';
33	import { NextRequest, NextResponse } from 'next/server';
34	
35	/**
36	 * GET /api/activity-logs
37	 *
38	 * Returns a paginated, filtered list of activity log entries. Managers and
39	 * location admins receive results scoped to their accessible resources; admins
40	 * and developers see all logs. When `search` is provided without conflicting
41	 * filters the results are ranked by relevance.
42	 *
43	 * Query params:
44	 * @param {number} [page] - Optional. Page number for pagination (default 1).
45	 * @param {number} [limit] - Optional. Records per page (default 50).
46	 * @param {string} [userId] - Optional. Filter by the acting user's ID.
47	 * @param {string} [username] - Optional. Case-insensitive regex match on username.
48	 * @param {string} [email] - Optional. Case-insensitive regex match on actor.email.
49	 * @param {string} [action] - Optional. Exact match on action type (e.g. 'CREATE', 'UPDATE').
50	 * @param {string} [resource] - Optional. Filter by resource type (e.g. 'machine', 'user').
51	 * @param {string} [resourceId] - Optional. Filter by the ID of the affected resource.
52	 * @param {string} [membershipLog] - Optional. 'true' or 'false' — filter membership-related logs.
53	 * @param {string} [startDate] - Optional. ISO date string; include logs at or after this timestamp.
54	 * @param {string} [endDate] - Optional. ISO date string; include logs at or before this timestamp.
55	 * @param {string} [search] - Optional. Full-text search across username, email, resourceName, details, description, and IDs.
56	 * @param {string} [sortBy] - Optional. Field to sort by (default 'timestamp').
57	 * @param {string} [sortOrder] - Optional. 'asc' or 'desc' (default 'desc').
58	 */
59	export async function GET(request: NextRequest) {
60	  const functionName = 'GET /api/activity-logs';
61	  const user = extractUserFromRequest(request);
62	
63	  return withApiAuth(
64	    request,
65	    async ({ user: currentUser, userRoles, isAdminOrDev }) => {
66	      const startTime = Date.now();
67	      const { searchParams } = new URL(request.url);
68	
69	      const page = parseInt(searchParams.get('page') || '1');
70	      const limit = parseInt(searchParams.get('limit') || '50');
71	      const skip = (page - 1) * limit;
72	
73	      const userId = searchParams.get('userId');
74	      const username = searchParams.get('username');
75	      const email = searchParams.get('email');
76	      const action = searchParams.get('action');
77	      const resource = searchParams.get('resource');
78	      const resourceId = searchParams.get('resourceId');
79	      const membershipLog = searchParams.get('membershipLog');
80	      const startDate = searchParams.get('startDate');
81	      const endDate = searchParams.get('endDate');
82	      const search = searchParams.get('search');
83	
84	      const sortBy = searchParams.get('sortBy') || 'timestamp';
85	      const sortOrder = searchParams.get('sortOrder') || 'desc';
86	
87	      const filter: Record<string, unknown> = { deletedAt: { $exists: false } };
88	      if (userId) filter.userId = userId;
89	      if (username) filter.username = { $regex: username, $options: 'i' };
90	      if (email) filter['actor.email'] = { $regex: email, $options: 'i' };
91	      if (action) filter.action = action;
92	      if (resource) filter.resource = resource;
93	      if (resourceId) filter.resourceId = resourceId;
94	      if (membershipLog !== null)
95	        filter.membershipLog = membershipLog === 'true';
96	
97	      if (startDate || endDate) {
98	        filter.timestamp = {} as Record<string, Date>;
99	        if (startDate)
100	          (filter.timestamp as Record<string, Date>).$gte = new Date(startDate);
101	        if (endDate)
102	          (filter.timestamp as Record<string, Date>).$lte = new Date(endDate);
103	      }
104	
105	      if (search && !username && !email && !resourceId) {
106	        filter.$or = [
107	          { username: { $regex: search, $options: 'i' } },
108	          { 'actor.email': { $regex: search, $options: 'i' } },
109	          { resourceName: { $regex: search, $options: 'i' } },
110	          { description: { $regex: search, $options: 'i' } },
111	          { details: { $regex: search, $options: 'i' } },
112	          { _id: { $regex: search, $options: 'i' } },
113	          { resourceId: { $regex: search, $options: 'i' } },
114	          { userId: { $regex: search, $options: 'i' } },
115	          { ipAddress: { $regex: search, $options: 'i' } },
116	        ];
117	      }
118	
119	      const isManager = userRoles.includes('manager') && !isAdminOrDev;
120	      const isLocationAdmin =
121	        userRoles.includes('location admin') && !isAdminOrDev && !isManager;
122	
123	      const userWithEntities = currentUser as {
124	        assignedLicencees?: string[];
125	        assignedLocations?: string[];
126	      };
127	
128	      if (isManager && (userWithEntities.assignedLicencees?.length ?? 0) > 0) {
129	        const currentUserLicencees = userWithEntities.assignedLicencees;
130	        const [locations, machines, users] = await Promise.all([
131	          GamingLocations.find({
132	            'rel.licencee': { $in: currentUserLicencees },
133	          })
134	            .select('_id')
135	            .lean<GamingLocationDocument[]>(),
136	          Machine.find({}).select('_id gamingLocation').lean<GamingMachine[]>(),
137	          User.find({ assignedLicencees: { $in: currentUserLicencees } })
138	            .select('_id')
139	            .lean<LeanUserDocument[]>(),
140	        ]);
141	
142	        const locationIds = locations.map(l => String(l._id));
143	        const machineLocationIds = new Set(locationIds);
144	        const machineIds = machines
145	          .filter(m => machineLocationIds.has(String(m.gamingLocation)))
146	          .map(m => String(m._id));
147	        const userIds = users.map(u => String(u._id));
148	
149	        filter.$or = [
150	          { resource: 'location', resourceId: { $in: locationIds } },
151	          { resource: 'machine', resourceId: { $in: machineIds } },
152	          { resource: 'cabinet', resourceId: { $in: machineIds } },
153	          { resource: 'user', resourceId: { $in: userIds } },
154	          { userId: { $in: userIds } },
155	        ];
156	      } else if (
157	        isLocationAdmin &&
158	        (userWithEntities.assignedLocations?.length ?? 0) > 0
159	      ) {
160	        const currentUserLocations =
161	          userWithEntities.assignedLocations?.map((id: string) => String(id)) ??
162	          [];
163	        const machines = await Machine.find({
164	          gamingLocation: { $in: currentUserLocations },
165	        })
166	          .select('_id')
167	          .lean<GamingMachine[]>();
168	        const machineIds = machines.map(m => String(m._id));
169	        const users = await User.find({
170	          assignedLocations: { $in: currentUserLocations },
171	        })
172	          .select('_id')
173	          .lean<LeanUserDocument[]>();
174	        const userIds = users.map(u => String(u._id));
175	
176	        filter.$or = [
177	          { resource: 'location', resourceId: { $in: currentUserLocations } },
178	          { resource: 'machine', resourceId: { $in: machineIds } },
179	          { resource: 'cabinet', resourceId: { $in: machineIds } },
180	          { resource: 'user', resourceId: { $in: userIds } },
181	          { userId: { $in: userIds } },
182	        ];
183	      }
184	
185	      const sort: Record<string, 1 | -1> = {
186	        [sortBy]: sortOrder === 'asc' ? 1 : -1,
187	      };
188	
189	      let logs, totalCount;
190	      if (search && !username && !email && !resourceId) {
191	        const searchLower = search.toLowerCase().trim();
192	        const pipeline = [
193	          { $match: filter },
194	          {
195	            $addFields: {
196	              relevance: {
197	                $add: [
198	                  {
199	                    $cond: [
200	                      {
201	                        $regexMatch: {
202	                          input: '$username',
203	                          regex: `^${searchLower}`,
204	                          options: 'i',
205	                        },
206	                      },
207	                      20,
208	                      0,
209	                    ],
210	                  },
211	                  {
212	                    $cond: [
213	                      {
214	                        $regexMatch: {
215	                          input: '$actor.email',
216	                          regex: `^${searchLower}`,
217	                          options: 'i',
218	                        },
219	                      },
220	                      15,
221	                      0,
222	                    ],
223	                  },
224	                  {
225	                    $cond: [
226	                      {
227	                        $regexMatch: {
228	                          input: { $toString: '$_id' },
229	                          regex: `^${searchLower}`,
230	                          options: 'i',
231	                        },
232	                      },
233	                      10,
234	                      0,
235	                    ],
236	                  },
237	                  {
238	                    $cond: [
239	                      {
240	                        $regexMatch: {
241	                          input: '$description',
242	                          regex: `^${searchLower}`,
243	                          options: 'i',
244	                        },
245	                      },
246	                      5,
247	                      0,
248	                    ],
249	                  },
250	                  {
251	                    $cond: [
252	                      {
253	                        $regexMatch: {
254	                          input: '$ipAddress',
255	                          regex: `^${searchLower}`,
256	                          options: 'i',
257	                        },
258	                      },
259	                      5,
260	                      0,
261	                    ],
262	                  },
263	                ],
264	              },
265	            },
266	          },
267	          { $sort: { relevance: -1, timestamp: -1 } as Record<string, 1 | -1> },
268	          { $skip: skip },
269	          { $limit: limit },
270	        ];
271	        [logs, totalCount] = await Promise.all([
272	          ActivityLog.aggregate(pipeline),
273	          ActivityLog.countDocuments(filter),
274	        ]);
275	      } else {
276	        [logs, totalCount] = await Promise.all([
277	          ActivityLog.find(filter)
278	            .sort(sort)
279	            .skip(skip)
280	            .limit(limit)
281	            .lean<ActivityLogDocument[]>(),
282	          ActivityLog.countDocuments(filter),
283	        ]);
284	      }
285	
286	      const duration = Date.now() - startTime;
287	      logRouteFetch(
288	        functionName,
289	        'GET',
290	        '/api/activity-logs',
291	        logs.length,
292	        user,
293	        duration
294	      );
295	
296	      return NextResponse.json({
297	        success: true,
298	        data: {
299	          activities: logs,
300	          pagination: {
301	            currentPage: page,
302	            totalPages: Math.ceil(totalCount / limit),
303	            totalCount,
304	            limit,
305	          },
306	        },
307	      });
308	    }
309	  );
310	}
