312	/**
313	 * POST /api/activity-logs
314	 *
315	 * Creates a new activity log entry. Called internally by server actions and
316	 * API routes after performing auditable operations.
317	 *
318	 * Body fields:
319	 * @param {string} action - Required. The action performed (e.g. 'CREATE', 'UPDATE', 'DELETE').
320	 * @param {string} resource - Required. The resource type affected (e.g. 'machine', 'user').
321	 * @param {string} resourceId - Required. The ID of the affected resource.
322	 * @param {string} userId - Required. ID of the user performing the action.
323	 * @param {string} username - Required. Username (or email) of the actor.
324	 * @param {string} [userRole] - Optional. Role of the acting user, stored in actor.role.
325	 * @param {string} [resourceName] - Optional. Human-readable name of the affected resource.
326	 * @param {string} [details] - Optional. Free-text description of what changed.
327	 * @param {string} [description] - Optional. Short summary line for display.
328	 * @param {object} [actor] - Optional. Full actor object `{ id, email, role }` — overrides derived actor.
329	 * @param {Array} [changes] - Optional. Explicit list of `{ field, oldValue, newValue }` change records.
330	 * @param {object} [previousData] - Optional. Full document state before the change (auto-diffs with newData if both provided).
331	 * @param {object} [newData] - Optional. Full document state after the change (auto-diffs with previousData if both provided).
332	 */
333	export async function POST(request: NextRequest) {
334	  const startTime = Date.now();
335	  const functionName = 'POST /api/activity-logs';
336	  const user = extractUserFromRequest(request);
337	
338	  return withApiAuth(request, async () => {
339	    const body = await request.json();
340	    const { action, resource, resourceId, userId, username, userRole } = body;
341	
342	    if (!action || !resource || !resourceId || !userId || !username) {
343	      logRouteError(
344	        functionName,
345	        'POST',
346	        '/api/activity-logs',
347	        'Missing required fields',
348	        user
349	      );
350	      return NextResponse.json(
351	        { success: false, error: 'Missing required fields' },
352	        { status: 400 }
353	      );
354	    }
355	
356	    let changes = body.changes || [];
357	    if (body.previousData && body.newData) {
358	      changes = calculateChanges(body.previousData, body.newData);
359	    } else if (body.newData) {
360	      changes = calculateChanges({}, body.newData);
361	    } else if (body.previousData) {
362	      changes = mapDeletedFieldsToChanges(body.previousData);
363	    }
364	
365	    const ipInfo = getIPInfo(request);
366	    const formattedIP = formatIPForDisplay(ipInfo);
367	    const activityLogId = await generateMongoId();
368	
369	    const activityLog = new ActivityLog({
370	      _id: activityLogId,
371	      timestamp: new Date(),
372	      userId,
373	      username,
374	      action,
375	      resource,
376	      resourceId,
377	      resourceName: body.resourceName,
378	      details: body.details,
379	      description: body.description,
380	      actor: body.actor || {
381	        id: userId,
382	        email: username,
383	        role: userRole || 'user',
384	      },
385	      ipAddress: formattedIP,
386	      userAgent: ipInfo.userAgent,
387	      changes: changes,
388	      previousData: body.previousData,
389	      newData: body.newData,
390	    });
391	
392	    await activityLog.save();
393	
394	    const duration = Date.now() - startTime;
395	    logRouteCreate(
396	      functionName,
397	      'POST',
398	      '/api/activity-logs',
399	      1,
400	      user,
401	      duration
402	    );
403	
404	    return NextResponse.json({ success: true, data: { activityLog } });
405	  });
406	}
