408	/**
409	 * DELETE /api/activity-logs
410	 *
411	 * Deletes all activity logs from the database. Restricted to developers only.
412	 */
413	export async function DELETE(request: NextRequest): Promise<Response> {
414	  const startTime = Date.now();
415	  const functionName = 'DELETE /api/activity-logs';
416	  const user = extractUserFromRequest(request);
417	
418	  return withApiAuth(request, async ({ userRoles }) => {
419	    const isDeveloper = userRoles.some(
420	      role => role.toLowerCase() === 'developer'
421	    );
422	    if (!isDeveloper) {
423	      logRouteError(
424	        functionName,
425	        'DELETE',
426	        '/api/activity-logs',
427	        'Forbidden - developer role required',
428	        user
429	      );
430	      return NextResponse.json(
431	        {
432	          success: false,
433	          message: 'Forbidden: Only developers can clear activity logs',
434	        },
435	        { status: 403 }
436	      );
437	    }
438	
439	    const deleteResult = await ActivityLog.deleteMany({});
440	
441	    const duration = Date.now() - startTime;
442	    logRouteDelete(
443	      functionName,
444	      'DELETE',
445	      '/api/activity-logs',
446	      deleteResult.deletedCount || 0,
447	      user,
448	      duration
449	    );
450	
451	    return NextResponse.json({
452	      success: true,
453	      message: `Successfully cleared all activity logs (${deleteResult.deletedCount} entries).`,
454	    });
455	  });
456	}
