1	/**
2	 * Activity Log by ID API Route
3	 *
4	 * Handles deletion of individual activity logs.
5	 * Supports both soft and hard delete, restricted to developers.
6	 *
7	 * @module app/api/activity-logs/[id]/route
8	 */
9	
10	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
11	import { ActivityLog } from '@/app/api/lib/models/activityLog';
12	import {
13	  logRouteDelete,
14	  logRouteError,
15	  extractUserFromRequest,
16	} from '@/app/api/lib/utils/routeLogger';
17	import { NextRequest, NextResponse } from 'next/server';
18	
19	/**
20	 * DELETE /api/activity-logs/[id]
21	 *
22	 * Deletes a single activity log entry by ID. Restricted to developers only.
23	 * Soft delete sets `deletedAt`; hard delete permanently removes the document.
24	 *
25	 * Path params:
26	 * @param id         {string}  Required. The ID of the activity log entry to delete.
27	 *
28	 * Query params:
29	 * @param deleteType {string}  Optional. 'soft' (default) or 'hard'. Hard delete is permanent and requires developer role.
30	 */
31	export async function DELETE(request: NextRequest): Promise<Response> {
32	  const startTime = Date.now();
33	  const functionName = 'DELETE /api/activity-logs/[id]';
34	  const user = extractUserFromRequest(request);
35	
36	  return withApiAuth(request, async ({ isAdminOrDev, userRoles }) => {
37	    const { pathname } = request.nextUrl;
38	    const id = pathname.split('/').pop();
39	    if (!id) {
40	      logRouteError(
41	        functionName,
42	        'DELETE',
43	        '/api/activity-logs/[id]',
44	        'Activity log ID is required',
45	        user
46	      );
47	      return NextResponse.json(
48	        { success: false, message: 'Activity log ID is required' },
49	        { status: 400 }
50	      );
51	    }
52	
53	    const isDeveloper = userRoles.some(
54	      role => role.toLowerCase() === 'developer'
55	    );
56	    if (!isDeveloper && !isAdminOrDev) {
57	      logRouteError(
58	        functionName,
59	        'DELETE',
60	        '/api/activity-logs/[id]',
61	        'Forbidden - developer role required',
62	        user
63	      );
64	      return NextResponse.json(
65	        {
66	          success: false,
67	          message: 'Forbidden: Only developers can delete activity logs',
68	        },
69	        { status: 403 }
70	      );
71	    }
72	
73	    const { searchParams } = new URL(request.url);
74	    const deleteType = (searchParams.get('deleteType') || 'soft') as
75	      | 'soft'
76	      | 'hard';
77	
78	    if (deleteType === 'hard') {
79	      const deleteResult = await ActivityLog.deleteOne({ _id: id });
80	      if (deleteResult.deletedCount === 0) {
81	        logRouteError(
82	          functionName,
83	          'DELETE',
84	          '/api/activity-logs/[id]',
85	          `Activity log not found: ${id}`,
86	          user
87	        );
88	        return NextResponse.json(
89	          { success: false, message: 'Activity log not found' },
90	          { status: 404 }
91	        );
92	      }
93	    } else {
94	      const updateResult = await ActivityLog.findOneAndUpdate(
95	        { _id: id },
96	        { deletedAt: new Date() },
97	        { new: true }
98	      );
99	      if (!updateResult) {
100	        logRouteError(
101	          functionName,
102	          'DELETE',
103	          '/api/activity-logs/[id]',
104	          `Activity log not found: ${id}`,
105	          user
106	        );
107	        return NextResponse.json(
108	          { success: false, message: 'Activity log not found' },
109	          { status: 404 }
110	        );
111	      }
112	    }
113	
114	    const duration = Date.now() - startTime;
115	    logRouteDelete(
116	      functionName,
117	      'DELETE',
118	      '/api/activity-logs/[id]',
119	      1,
120	      user,
121	      duration
122	    );
123	
124	    return NextResponse.json({ success: true });
125	  });
126	}
