1	/**
2	 * GET /api/rates
3	 *
4	 * Returns the current in-memory exchange rate table and list of supported
5	 * currency codes. Called by the currency conversion utilities and any UI
6	 * that needs to display amounts in non-base currencies. No authentication
7	 * required. Rates are sourced from static configuration, not a live feed.
8	 *
9	 * Query parameters:
10	 * @param includeMetadata {boolean} Optional. When 'true', the response includes a
11	 *   'currencyInfo' array with the full name and symbol for each available currency
12	 *   code (e.g. { code: 'TTD', name: 'Trinidad and Tobago Dollar', symbol: 'TT$' }).
13	 *
14	 * @module app/api/rates/route
15	 */
16	
17	import {
18	  getAvailableCurrencies,
19	  getCurrencyName,
20	  getCurrencySymbol,
21	  getExchangeRates,
22	} from '@/lib/helpers/rates';
23	import type { CurrencyCode } from '@/shared/types/currency';
24	import { NextRequest, NextResponse } from 'next/server';
25	import {
26	  logRouteFetch,
27	  logRouteError,
28	  extractUserFromRequest,
29	} from '@/app/api/lib/utils/routeLogger';
30	
31	export async function GET(request: NextRequest) {
32	  const startTime = Date.now();
33	  const functionName = 'GET /api/rates';
34	  const user = extractUserFromRequest(request);
35	
36	  try {
37	    // ============================================================================
38	    // STEP 1: Parse query parameters
39	    // ============================================================================
40	    const { searchParams } = new URL(request.url);
41	    const includeMetadata = searchParams.get('includeMetadata') === 'true';
42	
43	    // ============================================================================
44	    // STEP 2: Fetch exchange rates and available currencies
45	    // ============================================================================
46	    const exchangeRates = getExchangeRates();
47	    const availableCurrencies = getAvailableCurrencies();
48	
49	    // ============================================================================
50	    // STEP 3: Build response with optional metadata
51	    // ============================================================================
52	    const response = {
53	      success: true,
54	      data: {
55	        rates: exchangeRates,
56	        baseCurrency: 'USD' as CurrencyCode,
57	        availableCurrencies,
58	        timestamp: new Date().toISOString(),
59	        ...(includeMetadata && {
60	          currencyInfo: availableCurrencies.map(currency => ({
61	            code: currency,
62	            name: getCurrencyName(currency),
63	            symbol: getCurrencySymbol(currency),
64	          })),
65	        }),
66	      },
67	    };
68	
69	    // ============================================================================
70	    // STEP 4: Return rates and currency information
71	    // ============================================================================
72	    const duration = Date.now() - startTime;
73	    if (duration > 500) {
74	      console.warn(`[Rates API] Completed in ${duration}ms`);
75	    }
76	
77	    logRouteFetch(functionName, 'GET', '/api/rates', 1, user, duration);
78	    return NextResponse.json(response);
79	  } catch (error) {
80	    const duration = Date.now() - startTime;
81	    const errorMessage =
82	      error instanceof Error ? error.message : 'Unknown error';
83	    console.error(`[Rates API] Error after ${duration}ms:`, errorMessage);
84	    logRouteError(functionName, 'GET', '/api/rates', errorMessage, user);
85	    return NextResponse.json(
86	      {
87	        success: false,
